create table if not exists profiles(id uuid primary key,email text,plan text default 'free',stripe_customer_id text,created_at timestamptz default now());
create table if not exists customers(id uuid primary key default gen_random_uuid(),user_id uuid,name text not null,phone text,email text,address text,archived boolean default false,created_at timestamptz default now());
create table if not exists invoices(id uuid primary key default gen_random_uuid(),user_id uuid,invoice_number text,customer_name text,customer_phone text,customer_email text,customer_address text,status text,currency text,language text,template_id text,issue_date text,due_date text,notes text,items jsonb default '[]',created_at timestamptz default now());
create table if not exists usage_limits(id uuid primary key default gen_random_uuid(),user_id uuid,month_key text,invoices_created integer default 0,ai_generations integer default 0,reminders_sent integer default 0,created_at timestamptz default now());
